import React, { useState, useCallback, useEffect } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { TrialBalanceLineDto } from '../../../services/kt/models';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';

import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const labels = reportPageLabels.canDoiPhatSinh;

const CanDoiPhatSinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [items, setItems] = useState<TrialBalanceLineDto[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    ktService.getTrialBalance({ month: Number(month), year: Number(year) })
      .then(res => setItems(res.items))
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, labels.loadError), type: 'error' })))
      .finally(() => setLoading(false));
  }, [month, year, dispatch]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) handleLoad(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [handleLoad]);

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-balance-scale-right" /> {labels.title}</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`erp-can-doi-phat-sinh-filters`}>
        <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
        <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
        <Button variant="primary" onClick={handleLoad} loading={loading}>{labels.reload}</Button>
        <ListSearchRefreshButtons testIdPrefix="erp-can-doi-phat-sinh" onSearch={handleLoad} onRefresh={handleLoad} showSearch={false} />
      </div>
      <div className={erp.tableCard}>
        {loading ? <div className={erp.loading}>{labels.loading}</div> : items.length === 0 ? <div className={erp.empty}>{labels.empty}</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th rowSpan={2}>{labels.colAccount}</th><th rowSpan={2}>{labels.colAccountName}</th>
                  <th colSpan={2} className={erp.colRight}>{labels.colOpening}</th>
                  <th colSpan={2} className={erp.colRight}>{labels.colPeriod}</th>
                  <th colSpan={2} className={erp.colRight}>{labels.colClosing}</th>
                </tr>
                <tr><th className={erp.colRight}>{labels.colDebit}</th><th className={erp.colRight}>{labels.colCredit}</th><th className={erp.colRight}>{labels.colDebit}</th><th className={erp.colRight}>{labels.colCredit}</th><th className={erp.colRight}>{labels.colDebit}</th><th className={erp.colRight}>{labels.colCredit}</th></tr>
              </thead>
              <tbody>{items.map(r => (
                <tr key={r.accountCode}>
                  <td><code>{r.accountCode}</code></td>
                  <td>{r.accountName}</td>
                  <td className={erp.colRight}>{formatVnd(r.openingDebit)}</td>
                  <td className={erp.colRight}>{formatVnd(r.openingCredit)}</td>
                  <td className={erp.colRight}>{formatVnd(r.periodDebit)}</td>
                  <td className={erp.colRight}>{formatVnd(r.periodCredit)}</td>
                  <td className={erp.colRight}>{formatVnd(r.closingDebit)}</td>
                  <td className={erp.colRight}>{formatVnd(r.closingCredit)}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default CanDoiPhatSinhPage;
